TRUNCATE TABLE excursions;

INSERT INTO excursions (sort_number, city, title, description, price_rub, duration, included, meeting_point, is_active) VALUES

-- Москва
(1, 'Москва', 'Обзорная экскурсия по Москве', 'Увидите главные символы столицы: Красную площадь, Кремль, храм Василия Блаженного, Арбат и Воробьёвы горы. Незаменимая экскурсия для первого знакомства с Москвой.', 2500, '4 часа', 'Профессиональный гид, трансфер из отеля и обратно', 'Забор из вашего отеля', true),

(2, 'Москва', 'Москва-Сити и деловой квартал', 'Экскурсия в небоскрёбы Москва-Сити с посещением смотровой площадки на 89 этаже. Захватывающий вид на весь город и рассказ об архитектуре современной Москвы.', 3200, '3 часа', 'Гид, трансфер, билет на смотровую площадку', 'Забор из вашего отеля', true),

(3, 'Москва', 'Золотое кольцо России — Сергиев Посад', 'Поездка в один из древнейших городов России. Посещение Троице-Сергиевой лавры — крупнейшего православного монастыря страны. Потрясающие купола, иконы и история.', 4500, '8 часов', 'Гид, комфортабельный транспорт, входные билеты в монастырь', 'Забор из вашего отеля', true),

-- Санкт-Петербург
(4, 'Санкт-Петербург', 'Белые ночи и центр Петербурга', 'Романтическая вечерняя прогулка по историческому центру во время белых ночей. Дворцовая площадь, Эрмитаж, Невский проспект, развод мостов. Незабываемое зрелище!', 3000, '4 часа', 'Гид, трансфер', 'Забор из вашего отеля', true),

(5, 'Санкт-Петербург', 'Эрмитаж — главный музей России', 'Экскурсия по залам Эрмитажа с профессиональным гидом. Увидите коллекцию импрессионистов, античные залы, рыцарский зал и сокровищницу. Пропустить невозможно.', 4000, '3.5 часа', 'Гид, билет в Эрмитаж', 'Вход в Эрмитаж (Дворцовая площадь)', true),

(6, 'Санкт-Петербург', 'Петергоф — фонтаны и дворцы', 'Загородная поездка в Петергоф — «русский Версаль». Большой дворец, знаменитые фонтаны «Самсон» и «Шахматная гора», регулярный парк. Лучше всего летом, когда фонтаны работают.', 5500, 'Целый день', 'Гид, трансфер, билеты в парк и дворец', 'Забор из вашего отеля', true),

-- Сочи
(7, 'Сочи', 'Роза Хутор — горная Швейцария России', 'Поездка на знаменитый горнолыжный курорт. Подъём на канатной дороге на высоту 2320 метров, потрясающие горные пейзажи, фотосессия среди облаков.', 3500, '6 часов', 'Гид, трансфер, подъём на канатной дороге', 'Забор из вашего отеля', true),

(8, 'Сочи', 'Абхазия — экзотика на один день', 'Поездка в Абхазию: озеро Рица в горах, Голубое озеро, Гегский водопад, Новоафонские пещеры. Для любителей дикой природы и нетронутой красоты.', 4800, '10 часов', 'Гид, трансфер, страховка на въезд, входные билеты', 'Забор из вашего отеля', true),

(9, 'Сочи', 'Дендрарий и парк «Ривьера»', 'Прогулка по знаменитому сочинскому дендрарию с экзотическими растениями и парку Ривьера. Идеально для семей с детьми. Канатная дорога с видом на море и горы.', 2200, '4 часа', 'Гид, трансфер, билеты', 'Забор из вашего отеля', true),

-- Казань
(10, 'Казань', 'Исторический Казанский Кремль', 'Сердце Казани — уникальное место, где мирно соседствуют мечеть Кул-Шариф и православный Благовещенский собор. История двух культур в одном месте.', 2800, '3.5 часа', 'Гид, трансфер, входные билеты', 'Забор из вашего отеля', true),

(11, 'Казань', 'Свияжск — остров-град', 'Поездка на остров Свияжск — объект UNESCO. Уникальный архитектурный ансамбль 16-17 веков, прогулка на теплоходе по Волге, рассказ об истории этой удивительной крепости.', 5000, '8 часов', 'Гид, трансфер, теплоход, входные билеты', 'Забор из вашего отеля', true),

-- Турция (международные)
(12, 'Стамбул', 'Главные достопримечательности Стамбула', 'Собор Святой Софии, Голубая мечеть, дворец Топкапы, Гранд Базар. Всё лучшее за один день с опытным русскоязычным гидом.', 4500, '8 часов', 'Русскоязычный гид, трансфер из отеля, входные билеты', 'Забор из вашего отеля', true),

(13, 'Анталья', 'Древние Сиде и Аспендос', 'Поездка к руинам античного города Сиде и хорошо сохранившемуся амфитеатру Аспендос. Тысячелетняя история Средиземноморья прямо перед вами.', 3800, '8 часов', 'Русскоязычный гид, трансфер, входные билеты', 'Забор из вашего отеля', true),

-- Дубай
(14, 'Дубай', 'Дубай Обзорная — небоскрёбы и пустыня', 'Бурдж-Халифа, торговый молл, старый Дубай, рынок золота. Опциональный вечерний тур в пустыню с ужином и шоу.', 5500, '6 часов', 'Русскоязычный гид, трансфер', 'Забор из вашего отеля', true),

-- Египет
(15, 'Хургада', 'Луксор — столица Древнего Египта', 'Карнакский храм, Луксорский храм, Долина царей (гробница Тутанхамона). Полное погружение в мир фараонов с однодневным перелётом из Хургады.', 12000, '12 часов', 'Перелёт, гид, входные билеты, обед', 'Аэропорт Хургады', true);
